function getID(){console.log("ID - "+document.getElementById("id_film").value),search(document.getElementById("id_film").value)}function search(e){console.log("SEARCH FILM - "+e);try{document.getElementById("yohoho").remove(),playVideo(e),console.log("DEL LAST VIDEO")}catch{playVideo(e)}}function playVideo(e){let t=document.createElement("div");t.id="yohoho",t.setAttribute("data-kinopoisk",e),document.getElementById("content").append(t);const o=document.createElement("script");o.src="//yohoho.cc/yo.js",document.getElementById("content").append(o)}